#!/bin/bash
set -e
PROJECT="/Users/jamespitts/Downloads/aa2-scan"

echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  AA2 CANON v28.4 — THREE FIXES"
echo "  1. Personal Care image corrected"
echo "  2. Hero images full width"
echo "  3. THE CHAUFFEUR restored"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

echo "FIX 1 — Writing correct Personal Care image..."
printf "%s" "" | base64 -d > "$PROJECT/assets/images/tab-care.jpg"
echo "  ✅ tab-care.jpg replaced"

echo "FIX 2 & 3 — Updating index.tsx and map.tsx..."
python3 - << 'PYEOF'
# Fix hero image width in index.tsx
f = "/Users/jamespitts/Downloads/aa2-scan/app/(tabs)/index.tsx"
t = open(f).read()
old = "heroImage:{width:200,height:140,marginBottom:16,borderRadius:12,opacity:0.85}"
new = "heroImage:{width:'100%',height:220,marginBottom:16,borderRadius:12,opacity:0.90}"
if old in t:
    t = t.replace(old, new)
    open(f,'w').write(t)
    print("  ✅ Hero image: full width")
else:
    print("  ⚠️  heroImage style not found — check manually")

# Fix THE CHAUFFEUR in map.tsx
f2 = "/Users/jamespitts/Downloads/aa2-scan/app/(tabs)/map.tsx"
t2 = open(f2).read()
if '<Text style={s.headerSub}>CHAUFFEUR</Text>' in t2:
    t2 = t2.replace('<Text style={s.headerSub}>CHAUFFEUR</Text>', '<Text style={s.headerSub}>THE CHAUFFEUR</Text>')
    open(f2,'w').write(t2)
    print("  ✅ THE CHAUFFEUR restored")
else:
    print("  ⚠️  CHAUFFEUR text not found — check manually")
PYEOF

echo ""
echo "Running bundle test..."
cd "$PROJECT"
npx expo export --platform android 2>&1 | tail -4

echo ""
echo "Committing and building..."
git add -A
git commit -m "Canon v28.4: care image fixed, heroes full width, THE CHAUFFEUR restored"
eas build --platform android --profile preview --clear-cache
